INSERT INTO `v1_7a4dd82129241c3a72e16eaba18a4d9a6f14a71757a19114fc3f63cdb258791e` VALUES (10040, 0.0, 0, "2020/04/30 12:00:00", 1, 24001, 1, 102601, 0.0, "2030/12/17 14:59:59", 24, 0.0, "リン", "あたしだって\nやるときはやるよ！");
INSERT INTO `v1_7a4dd82129241c3a72e16eaba18a4d9a6f14a71757a19114fc3f63cdb258791e` VALUES (10040, 0.0, 1, "2020/04/30 12:00:00", 1, 24002, 1, 102601, 0.0, "2030/12/17 14:59:59", 24, 0.0, "リン", "ふぅ…\nこれであたしの仕事は\n終わりだね");
INSERT INTO `v1_7a4dd82129241c3a72e16eaba18a4d9a6f14a71757a19114fc3f63cdb258791e` VALUES (10040, 0.0, 2, "2020/04/30 12:00:00", 1, 24003, 1, 102601, 0.0, "2030/12/17 14:59:59", 24, 0.0, "リン", "終わった終わった\n一人でもなんとか\nなるもんだね");
INSERT INTO `v1_7a4dd82129241c3a72e16eaba18a4d9a6f14a71757a19114fc3f63cdb258791e` VALUES (10040, 0.0, 3, "2020/04/30 12:00:00", 2, 24004, 2, 102601, 0.0, "2030/12/17 14:59:59", 24, 0.0, "リン", "やったね！\nこれでようやく\nサボれるよ…");
INSERT INTO `v1_7a4dd82129241c3a72e16eaba18a4d9a6f14a71757a19114fc3f63cdb258791e` VALUES (10040, 0.0, 4, "2020/04/30 12:00:00", 1, 24005, 1, 102601, 0.0, "2030/12/17 14:59:59", 24, 0.0, "リン", "チーズが欲しいなら\nきちんと働いて\n買いに来なよ");
INSERT INTO `v1_7a4dd82129241c3a72e16eaba18a4d9a6f14a71757a19114fc3f63cdb258791e` VALUES (10040, 0.0, 5, "2020/04/30 12:00:00", 2, 24006, 2, 102601, 0.0, "2030/12/17 14:59:59", 24, 0.0, "リン", "あたしを敵に回した\n恐ろしさ\n思い知ったか！");
INSERT INTO `v1_7a4dd82129241c3a72e16eaba18a4d9a6f14a71757a19114fc3f63cdb258791e` VALUES (10040, 0.0, 6, "2020/04/30 12:00:00", 2, 24007, 2, 102601, 0.0, "2030/12/17 14:59:59", 24, 0.0, "リン", "あたしも意外と\nやるもんでしょ？");
INSERT INTO `v1_7a4dd82129241c3a72e16eaba18a4d9a6f14a71757a19114fc3f63cdb258791e` VALUES (10040, 0.0, 7, "2020/04/30 12:00:00", 4, 24008, 4, 102601, 0.0, "2030/12/17 14:59:59", 24, 0.0, "リン", "疲れた…\nねずみの逃げ足\n速すぎるよ…");
INSERT INTO `v1_7a4dd82129241c3a72e16eaba18a4d9a6f14a71757a19114fc3f63cdb258791e` VALUES (10040, 0.0, 8, "2020/04/30 12:00:00", 4, 24009, 4, 102601, 0.0, "2030/12/17 14:59:59", 24, 0.0, "リン", "このままじゃ\nまっひ～に\n叱られちゃうよ");
INSERT INTO `v1_7a4dd82129241c3a72e16eaba18a4d9a6f14a71757a19114fc3f63cdb258791e` VALUES (10040, 0.0, 9, "2020/04/30 12:00:00", 4, 24010, 4, 102601, 0.0, "2030/12/17 14:59:59", 24, 0.0, "リン", "まじめに\nやったんだけどな…\n悔しいな～");
INSERT INTO `v1_7a4dd82129241c3a72e16eaba18a4d9a6f14a71757a19114fc3f63cdb258791e` VALUES (10040, 0.0, 10, "2020/04/30 12:00:00", 4, 24011, 4, 102601, 0.0, "2030/12/17 14:59:59", 24, 0.0, "リン", "やられた…\nねずみって意外と\nてごわいね");
INSERT INTO `v1_7a4dd82129241c3a72e16eaba18a4d9a6f14a71757a19114fc3f63cdb258791e` VALUES (10040, 0.0, 11, "2020/04/30 12:00:00", 4, 24012, 4, 102601, 0.0, "2030/12/17 14:59:59", 24, 0.0, "リン", "おのれ～\nあたしのチーズを\n盗みやがって～！");
INSERT INTO `v1_7a4dd82129241c3a72e16eaba18a4d9a6f14a71757a19114fc3f63cdb258791e` VALUES (10040, 1.81, 12, "2020/04/30 12:00:00", 1, 24013, 4, 102601, 0.0, "2030/12/17 14:59:59", 24, 0.0, "リン", "疲れた…\nけど、次こそは\n守り抜くよ…");
